  ('heelevel3-6f0ba476-moex-00657', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-d3ff7f6b', 'sub-heelevel3-6f0ba476-06', NULL, 'single_choice', '假設電動汽車需求的價格彈性為2，供給的價格彈性為0.9，如果政府針對每部電動汽車的購買， 補貼消費者5萬元，相對於沒有補貼的情況，補貼後，下列敘述何者正確？', '["消費者剩餘增加的幅度超過生產者剩餘增加的幅度", "消費者剩餘增加的幅度小於生者者剩餘增加的幅度", "生產者剩餘不變", "社會福利不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:33+00:00", "source_pdf_sha1": "b08f8b855b01", "answer_pdf_sha1": "82b5b8631449", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
